const e=JSON.parse('{"key":"v-06d76eae","path":"/posts/%E6%B5%8B%E7%BB%98/%E9%81%A5%E6%84%9F%E6%8A%80%E6%9C%AF.html","title":"遥感技术","lang":"en-US","frontmatter":{"description":"遥感技术 遥感技术详解 1. 概述 遥感（Remote Sensing），顾名思义，就是从远处感知目标。它是指在不直接接触目标物体的情况下，利用传感器获取目标物体的电磁波信息，并通过处理、分析和解译这些信息，来识别目标物体及其性质、状态和变化规律的一门综合性探测技术。 2. 基本原理 遥感技术的基本原理是基于一切物体都具有发射、反射和吸收电磁波的特性。不同物体对不同波段的电磁波的响应特性不同，因此可以通过分析传感器接收到的电磁波信息来识别和区分不同的物体。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%B5%8B%E7%BB%98/%E9%81%A5%E6%84%9F%E6%8A%80%E6%9C%AF.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:title","content":"遥感技术"}],["meta",{"property":"og:description","content":"遥感技术 遥感技术详解 1. 概述 遥感（Remote Sensing），顾名思义，就是从远处感知目标。它是指在不直接接触目标物体的情况下，利用传感器获取目标物体的电磁波信息，并通过处理、分析和解译这些信息，来识别目标物体及其性质、状态和变化规律的一门综合性探测技术。 2. 基本原理 遥感技术的基本原理是基于一切物体都具有发射、反射和吸收电磁波的特性。不同物体对不同波段的电磁波的响应特性不同，因此可以通过分析传感器接收到的电磁波信息来识别和区分不同的物体。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:37:55.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:37:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"遥感技术\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:37:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"遥感技术详解","slug":"遥感技术详解","link":"#遥感技术详解","children":[]}],"git":{"createdTime":1755319075000,"updatedTime":1755319075000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":3.41,"words":1024},"filePathRelative":"posts/测绘/遥感技术.md","localizedDate":"August 16, 2025","excerpt":"<h1> 遥感技术</h1>\\n<h2> 遥感技术详解</h2>\\n<p><strong>1. 概述</strong></p>\\n<p>遥感（Remote Sensing），顾名思义，就是从远处感知目标。它是指在不直接接触目标物体的情况下，利用传感器获取目标物体的电磁波信息，并通过处理、分析和解译这些信息，来识别目标物体及其性质、状态和变化规律的一门综合性探测技术。</p>\\n<p><strong>2. 基本原理</strong></p>\\n<p>遥感技术的基本原理是基于一切物体都具有发射、反射和吸收电磁波的特性。不同物体对不同波段的电磁波的响应特性不同，因此可以通过分析传感器接收到的电磁波信息来识别和区分不同的物体。</p>","autoDesc":true}');export{e as data};
